// Convert raw values to temperatures (divide by 10)
let temps = msg.payload.map(val => val / 10);

// Check for alarms
let alarms = [];
temps.forEach((temp, index) => {
    if (temp > 55) {
        alarms.push({sensor: index, level: 'CRITICAL', temp: temp});
    } else if (temp > 45) {
        alarms.push({sensor: index, level: 'WARNING', temp: temp});
    } else if (temp > 35) {
        alarms.push({sensor: index, level: 'CAUTION', temp: temp});
    }
});

msg.temperatures = temps;
msg.alarms = alarms;
msg.avgTemp = temps.reduce((a,b) => a+b, 0) / temps.length;

return msg;

// Handle alarms from various sources
if (msg.alarms && msg.alarms.length > 0) {
    // Set alarm coils based on alarm levels
    let coilStates = new Array(32).fill(false);

    msg.alarms.forEach(alarm => {
        if (alarm.sensor < 10) {
            // Temperature alarm
            coilStates[alarm.sensor] = true;
        }
    });

    // Prepare write to alarm coils
    msg.payload = coilStates.slice(0, 10);
    return msg;
}

return null;

// Track performance metrics
let metrics = flow.get('metrics') || {
    requests: 0,
    errors: 0,
    totalTime: 0,
    startTime: Date.now()
};

metrics.requests++;

if (msg.error) {
    metrics.errors++;
}

if (msg.responseTime) {
    metrics.totalTime += msg.responseTime;
}

// Calculate statistics
let runtime = (Date.now() - metrics.startTime) / 1000;
let stats = {
    totalRequests: metrics.requests,
    errorRate: (metrics.errors / metrics.requests * 100).toFixed(2) + '%',
    avgResponseTime: (metrics.totalTime / metrics.requests).toFixed(2) + 'ms',
    throughput: (metrics.requests / runtime).toFixed(2) + ' req/sec',
    uptime: runtime.toFixed(0) + ' seconds'
};

flow.set('metrics', metrics);
msg.performanceStats = stats;

return msg;

// Process batch results
let results = msg.payload;

msg.batchSummary = {
    temperatures: results.readTemps ? results.readTemps.map(v => v/10) : [],
    pressures: results.readPressures ? results.readPressures.map(v => v/10) : [],
    motorStatus: results.readMotorStatus || [],
    timestamp: new Date().toISOString()
};

return msg;
